BEGIN;

WITH tenant_and_user AS (
    SELECT
        t.id AS tenant_id,
        u.id AS user_id
    FROM tenants t
    JOIN users u ON u.tenant_id = t.id
    WHERE t.name = 'NoMa Klíma- és Hűtéstechnikai Kft.'
      AND u.email = 'floomatik@nomahutes.hu'
),
building_seed(name, address) AS (
    VALUES
        ('Emberi Erőforrások Minisztériuma', 'Budapest, Akadémia u. 3.'),
        ('Igazságügyi Minisztérium', 'Budapest, Kossuth tér 2-4.'),
        ('Kálmán tömb', 'Budapest, Kálmán tömb (Alkotmány u. 5.)'),
        ('Külgazdasági és Külügyminisztérium', 'Budapest, Naphegy tér 1.'),
        ('Nemzetgazdasági Minisztérium', 'Budapest, Vám u. 5-7.')
)
INSERT INTO buildings (tenant_id, name, address, created_by)
SELECT
    tau.tenant_id,
    seed.name,
    seed.address,
    tau.user_id
FROM tenant_and_user tau
CROSS JOIN building_seed seed
WHERE NOT EXISTS (
    SELECT 1
    FROM buildings b
    WHERE b.tenant_id = tau.tenant_id
      AND b.name = seed.name
);

