resolved_devices AS (
    SELECT
        tau.tenant_id,
        tau.user_id,
        sl.id AS location_id,
        seed.kind::device_kind AS kind,
        seed.tender_classification::tender_classification AS tender_classification,
        seed.maintenance_frequency_per_year,
        seed.brand,
        seed.model,
        seed.serial_number,
        seed.source_device_code
    FROM tenant_and_user tau
    JOIN device_seed seed ON TRUE
    JOIN buildings b
      ON b.tenant_id = tau.tenant_id
     AND b.name = seed.building_name
    JOIN site_locations sl
      ON sl.tenant_id = tau.tenant_id
     AND sl.building_id = b.id
     AND sl.floor IS NOT DISTINCT FROM seed.floor
     AND sl.wing IS NOT DISTINCT FROM seed.wing
     AND sl.room IS NOT DISTINCT FROM seed.room
     AND sl.location_description IS NOT DISTINCT FROM seed.location_description
)
INSERT INTO devices (
    tenant_id,
    location_id,
    kind,
    tender_classification,
    maintenance_frequency_per_year,
    brand,
    model,
    serial_number,
    source_device_code,
    created_by
)
SELECT
    rd.tenant_id,
    rd.location_id,
    rd.kind,
    rd.tender_classification,
    rd.maintenance_frequency_per_year,
    rd.brand,
    rd.model,
    rd.serial_number,
    rd.source_device_code,
    rd.user_id
FROM resolved_devices rd
WHERE NOT EXISTS (
    SELECT 1
    FROM devices d
    WHERE d.tenant_id = rd.tenant_id
      AND (
          (rd.source_device_code IS NOT NULL AND d.source_device_code = rd.source_device_code)
          OR (
              rd.source_device_code IS NULL
              AND d.location_id IS NOT DISTINCT FROM rd.location_id
              AND d.kind = rd.kind
              AND d.tender_classification IS NOT DISTINCT FROM rd.tender_classification
              AND d.maintenance_frequency_per_year IS NOT DISTINCT FROM rd.maintenance_frequency_per_year
              AND d.brand IS NOT DISTINCT FROM rd.brand
              AND d.model IS NOT DISTINCT FROM rd.model
              AND d.serial_number IS NOT DISTINCT FROM rd.serial_number
          )
      )
);

COMMIT;
